import { useEffect, useMemo, useState } from "react";
import axios from "axios";
import ReactMarkdown from "react-markdown";
import remarkGfm from "remark-gfm";

const API_BASE = process.env.REACT_APP_API_BASE || "http://localhost:8002";
const ANALYZE_URL = `${API_BASE}/analyze-url`;
const ASK_URL = `${API_BASE}/ask-question`;
const SUBMIT_CREDS_URL = `${API_BASE}/submit-credentials`;
const END_SESSION_URL = `${API_BASE}/session/end`;

const isProbablyUrl = (value) => {
  const trimmed = (value || "").trim();
  return /^https?:\/\/\S+$/i.test(trimmed);
};

const parseApiError = (err) => {
  const status = err?.response?.status;
  const detail = err?.response?.data?.detail;

  if (detail && typeof detail === "object") {
    const message = typeof detail.message === "string" ? detail.message : "Request failed.";
    const authTypes = Array.isArray(detail.auth_types) ? detail.auth_types : [];
    return { status, message, authTypes };
  }

  if (typeof detail === "string") {
    return { status, message: detail, authTypes: [] };
  }

  return { status, message: "Failed to get response from server.", authTypes: [] };
};

function App() {
  const [context, setContext] = useState("");
  const [question, setQuestion] = useState("");
  const [sessionId, setSessionId] = useState("");
  const [activeUrl, setActiveUrl] = useState("");
  const [messages, setMessages] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const [authRequired, setAuthRequired] = useState(false);
  const [authTypes, setAuthTypes] = useState([]);
  const [email, setEmail] = useState("");
  const [username, setUsername] = useState("");
  const [password, setPassword] = useState("");
  const [otp, setOtp] = useState("");
  const [pin, setPin] = useState("");
  const [verificationCode, setVerificationCode] = useState("");

  const canSend = useMemo(
    () => question.trim().length > 0 && !loading && !authRequired,
    [question, loading, authRequired]
  );

  useEffect(() => {
    const handleBeforeUnload = () => {
      if (!sessionId) {
        return;
      }

      navigator.sendBeacon(
        END_SESSION_URL,
        new Blob([JSON.stringify({ session_id: sessionId })], { type: "application/json" })
      );
    };

    window.addEventListener("beforeunload", handleBeforeUnload);
    return () => window.removeEventListener("beforeunload", handleBeforeUnload);
  }, [sessionId]);

  const handleSend = async () => {
    const trimmedQuestion = question.trim();
    if (!trimmedQuestion || loading) {
      return;
    }

    setError("");
    setLoading(true);
    setMessages((prev) => [...prev, { role: "user", content: trimmedQuestion }]);

    try {
      axios.defaults.withCredentials = true;

      const maybeUrl = context.trim();
      const needsAnalyzeFirst = !activeUrl && isProbablyUrl(maybeUrl);

      if (needsAnalyzeFirst) {
        const analyzeResp = await axios.get(ANALYZE_URL, {
          params: { url: maybeUrl },
          headers: { "Content-Type": "application/json" }
        });
        const { login_required, auth_types, message, session_id, final_url } = analyzeResp.data;
        if (session_id) {
          setSessionId(session_id);
        }
        setActiveUrl(final_url || maybeUrl);
        setMessages((prev) => [...prev, { role: "assistant", content: message || "URL analyzed." }]);

        if (login_required) {
          setAuthRequired(true);
          setAuthTypes(auth_types || []);
          setMessages((prev) => [
            ...prev,
            {
              role: "assistant",
              content:
                "Login is required. Please provide the requested credentials below, then click **Submit Credentials**."
            }
          ]);
          setQuestion("");
          return;
        }
      }

      const targetUrl = activeUrl || (isProbablyUrl(context) ? context.trim() : "");
      const askResp = await axios.post(
        ASK_URL,
        { question: trimmedQuestion, ...(targetUrl ? { url: targetUrl } : {}) },
        { headers: { "Content-Type": "application/json" } }
      );
      const { answer, session_id } = askResp.data;
      if (session_id) {
        setSessionId(session_id);
      }
      setMessages((prev) => [...prev, { role: "assistant", content: answer }]);
      setQuestion("");
    } catch (err) {
      const apiError = parseApiError(err);
      setError(apiError.message);

      if (apiError.status === 401 && apiError.authTypes.length > 0) {
        setAuthRequired(true);
        setAuthTypes(apiError.authTypes);
        setMessages((prev) => [
          ...prev,
          {
            role: "assistant",
            content: `${apiError.message} Please provide the requested credentials below, then click **Submit Credentials**.`
          }
        ]);
      } else {
        setMessages((prev) => [...prev, { role: "assistant", content: "Error: " + apiError.message }]);
      }
    } finally {
      setLoading(false);
    }
  };

  const handleKeyDown = (event) => {
    if (event.key === "Enter" && !event.shiftKey) {
      event.preventDefault();
      handleSend();
    }
  };

  const handleNewChat = async () => {
    if (sessionId) {
      try {
        await axios.post(
          END_SESSION_URL,
          { session_id: sessionId },
          { headers: { "Content-Type": "application/json" } }
        );
      } catch {
        // Ignore cleanup failures; local reset still starts a new session.
      }
    }

    setSessionId("");
    setActiveUrl("");
    setMessages([]);
    setQuestion("");
    setContext("");
    setError("");
    setLoading(false);
    setAuthRequired(false);
    setAuthTypes([]);
    setEmail("");
    setUsername("");
    setPassword("");
    setOtp("");
    setPin("");
    setVerificationCode("");
  };

  const handleSubmitCredentials = async () => {
    if (!activeUrl || loading) {
      return;
    }
    setError("");
    setLoading(true);
    try {
      axios.defaults.withCredentials = true;
      const resp = await axios.post(
        SUBMIT_CREDS_URL,
        {
          url: activeUrl,
          ...(email.trim() ? { email: email.trim() } : {}),
          ...(username.trim() ? { username: username.trim() } : {}),
          ...(password ? { password } : {}),
          ...(otp.trim() ? { otp: otp.trim() } : {}),
          ...(pin.trim() ? { pin: pin.trim() } : {}),
          ...(verificationCode.trim() ? { verification_code: verificationCode.trim() } : {})
        },
        { headers: { "Content-Type": "application/json" } }
      );
      const { authenticated, message, next_required, session_id } = resp.data;
      if (session_id) {
        setSessionId(session_id);
      }
      setMessages((prev) => [...prev, { role: "assistant", content: message || "Credentials submitted." }]);

      if (authenticated) {
        setAuthRequired(false);
        setAuthTypes([]);
        setOtp("");
        setPin("");
        setVerificationCode("");
        return;
      }

      setAuthRequired(true);
      setAuthTypes(next_required || []);
    } catch (err) {
      const apiError = parseApiError(err);
      setError(apiError.message || "Failed to submit credentials.");
      setMessages((prev) => [...prev, { role: "assistant", content: "Error: " + (apiError.message || "") }]);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="page">
      <div className="shell">
        <header className="topbar">
          <div className="title-row">
            <h1>Context-Aware AI Chatbot</h1>
            <div className="status-pills">
              <span className={`pill ${sessionId ? "pill-live" : ""}`}>
                {sessionId ? "Session Active" : "No Session"}
              </span>
              <span className={`pill ${loading ? "pill-wait" : "pill-ready"}`}>
                {loading ? "Generating..." : "Ready"}
              </span>
              <button className="new-chat-btn" onClick={handleNewChat} disabled={loading}>
                New Chat
              </button>
            </div>
          </div>
          <p></p>
        </header>

        <section className="inputs">
          <label>
            URL or Text (optional, first message only)
            <textarea
              placeholder="https://example.com OR paste context text..."
              value={context}
              onChange={(e) => setContext(e.target.value)}
              disabled={loading || !!sessionId}
              rows={4}
            />
          </label>
        </section>

        {authRequired && (
          <section className="inputs">
            <label>
              Credentials required: {(authTypes || []).join(", ") || "unknown"}
              <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: "12px", marginTop: "12px" }}>
                {(authTypes.includes("email_password") || authTypes.includes("password")) && (
                  <input
                    placeholder="Email"
                    value={email}
                    onChange={(e) => setEmail(e.target.value)}
                    disabled={loading}
                  />
                )}
                {(authTypes.includes("username_password") || authTypes.includes("password")) && (
                  <input
                    placeholder="Username"
                    value={username}
                    onChange={(e) => setUsername(e.target.value)}
                    disabled={loading}
                  />
                )}
                {(authTypes.includes("email_password") ||
                  authTypes.includes("username_password") ||
                  authTypes.includes("password")) && (
                  <input
                    placeholder="Password"
                    type="password"
                    value={password}
                    onChange={(e) => setPassword(e.target.value)}
                    disabled={loading}
                  />
                )}
                {authTypes.includes("otp") && (
                  <input placeholder="OTP" value={otp} onChange={(e) => setOtp(e.target.value)} disabled={loading} />
                )}
                {authTypes.includes("pin") && (
                  <input placeholder="PIN" value={pin} onChange={(e) => setPin(e.target.value)} disabled={loading} />
                )}
                {authTypes.includes("verification_code") && (
                  <input
                    placeholder="Verification code"
                    value={verificationCode}
                    onChange={(e) => setVerificationCode(e.target.value)}
                    disabled={loading}
                  />
                )}
              </div>
              {(authTypes.includes("sso") || authTypes.includes("captcha")) && (
                <p style={{ marginTop: "10px" }}>
                  This site may require SSO/CAPTCHA, which can block automation. If it fails, try a simpler site or a
                  page without CAPTCHA.
                </p>
              )}
              <button style={{ marginTop: "12px" }} onClick={handleSubmitCredentials} disabled={loading}>
                {loading ? "Submitting..." : "Submit Credentials"}
              </button>
            </label>
          </section>
        )}

        <section className="chat">
          <div className="messages">
            {messages.length === 0 && (
              <div className="empty">
                <h3>Start your chat</h3>
                <p>Add URL/text context (optional), then ask your first question.</p>
                <p>Follow-ups like "Explain more" or "Give examples" will use the same session.</p>
              </div>
            )}
            {messages.map((msg, index) => (
              <div key={`${msg.role}-${index}`} className={`msg msg-${msg.role}`}>
                <div className="badge">{msg.role === "user" ? "You" : "Assistant"}</div>
                <div className="bubble">
                  {msg.role === "assistant" ? (
                    <ReactMarkdown remarkPlugins={[remarkGfm]}>{msg.content}</ReactMarkdown>
                  ) : (
                    msg.content
                  )}
                </div>
              </div>
            ))}
            {loading && (
              <div className="loading">
                <span className="dots" />
                Thinking...
              </div>
            )}
          </div>

          <div className="composer">
            <textarea
              placeholder="Ask a question..."
              value={question}
              onChange={(e) => setQuestion(e.target.value)}
              onKeyDown={handleKeyDown}
              rows={3}
              disabled={loading}
            />
            <button onClick={handleSend} disabled={!canSend}>
              {loading ? "Sending..." : "Send"}
            </button>
          </div>
        </section>

        {error && <div className="error">{error}</div>}
      </div>
    </div>
  );
}

export default App;
